def format_schema(records):
    lines = []
    for r in records:
        lines.append(f"- {r['column_name']}: {r['data_type'] }")
    return "\n".join(lines)


async def fetch_context(embedded_user_input: str, tableschema_dbconnection_pool: Pool) -> str:
    """
    Fetch context asynchronously from the database based on the embedded user input.

    Args:
        embedded_user_input (str): A string representation of the user's input embedding, used to find the closest matching context in the database.
        pool (asyncpg.Pool): An instance of the database connection pool to execute queries.

    Returns:
        table_schema (str): A string containing the schema of the relevant database tables.
        context_for_sql_generation (str): A string containing examples of user inputs and corresponding SQL queries for generating SQL.
        context_for_user_response (str): A string containing examples of user inputs and corresponding assistant responses for generating chat responses.
    """

    if not embedded_user_input or not isinstance(embedded_user_input, str):
        logging.error("embedded_user_input must be a non-empty string but given %s", embedded_user_input)
        raise ValueError(f"embedded_user_input must be a non-empty string but given {embedded_user_input}")
    
    knowledgebase_dbconnection_pool = await connect_to_db(database_name=KNOWLEDGEBASE_DATABASE_NAME)
    
    if not knowledgebase_dbconnection_pool or not isinstance(knowledgebase_dbconnection_pool, Pool):
        logging.error("Invalid input: pool must be a valid asyncpg.Pool instance. Received: %s", knowledgebase_dbconnection_pool)
        raise ValueError(f"pool must be valid asyncpg.Pool instance but given {knowledgebase_dbconnection_pool}")
    
    if not tableschema_dbconnection_pool or not isinstance(tableschema_dbconnection_pool, Pool):
        logging.error("Invalid input: pool must be a valid asyncpg.Pool instance. Received: %s", tableschema_dbconnection_pool)
        raise ValueError(f"pool must be valid asyncpg.Pool instance but given {tableschema_dbconnection_pool}")
    
    try:
        start_time = time()
        async with knowledgebase_dbconnection_pool.acquire() as conn:
            # await conn.execute(f"SET search_path TO {KNOWLEDGEBASE_SCHEMA_NAME}")
            rows = await conn.fetch("""SELECT kbe_id, kbe_reference_tables, kbe_user_input, kbe_sql_query, kbe_user_response 
                                    FROM ai.knowledge_base_examples kbe
                                    ORDER BY kbe_user_input_embedding <=> $1
                                    LIMIT $2;
                                    """,embedded_user_input, KB_CONTEXT_LIMIT)
        
        # If no context is available return empty string
        if not rows:
            processing_time = time() - start_time
            logging.info("No Context Available. Processing Time: %s", processing_time)
            return "", "", ""
        
        context_for_sql_generation: str = ""
        context_for_user_response: str = ""
        temp_table_names: List[List] = []
        table_schema = ""
        n = 1
            
        for row in rows:
            id, table_name, user_input_example, sql_query_example, user_response_example = row
            
            temp_table_names.append(table_name)

            context_for_sql_generation += f"Example {n} - \nUser: {user_input_example}\nAssistant: {sql_query_example}\n\n"
            
            if n <= 10:
                context_for_user_response += f"Example {n} - \nUser: {user_input_example}\nAssistant: {user_response_example}\n\n"
            
            n += 1
        
        table_names = list(set().union(*temp_table_names))

        async with tableschema_dbconnection_pool.acquire() as conn:
            # await conn.execute(f"SET search_path TO {DATA_SCHEMA}")
            for table_name in table_names:
                schema = await conn.fetch("""SELECT column_name, data_type
                                        FROM information_schema.columns
                                        WHERE table_name = $1 and table_schema = $2;
                                        """, table_name, DATA_SCHEMA)
                
                # table = tabulate(schema, headers="keys", tablefmt="github")
                
                # table_schema += f"Table Schema of {table_name}:\n\n{schema}\n\n"
                formatted_schema = format_schema(schema)
                table_schema += f"Table Schema of {table_name}:\n\n{formatted_schema}\n\n"
            
            # print(table_names)
            # print(table_schema)
            # print(context_for_sql_generation)
            # print(context_for_chat_response)
        
        processing_time = time() - start_time
        logging.info("Context Retrieval Time: %s", processing_time)

        return table_schema, context_for_sql_generation, context_for_user_response
    
    except ConnectionFailureError as conn_err:
        logging.error("Database connection pool error: %s", conn_err, exc_info=True)
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Failed to acquire database connection.")
    
    except Exception as e:
        logging.error("An unexpected error occurred in fetch_context: %s", e, exc_info=True)
        raise RuntimeError(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="An unexpected error occurred while fetching context.")

def format_sql_query(sql, facm_code):
    """
    Remove triple backticks and optional 'sql' label from the query string.
    """
    sql = re.sub(r"^```(sql)?\s*|```$", "", sql.strip(), flags=re.IGNORECASE)
    
    facm_code_str = ",".join(f"'{code}'" for code in facm_code)

    # sql_with_facility_code = sql.replace("'<facilitycode>'", facm_code_str)
    sql_with_facility_code = re.sub(r"'<facilitycode>'|<facilitycode>", facm_code_str, sql)

    return sql_with_facility_code


def clean_sql_query(sql):
    """
    Remove triple backticks and optional 'sql' label from the query string.
    """
    return re.sub(r"^```(sql)?\s*|```$", "", sql.strip(), flags=re.IGNORECASE)

async def execute_ai_generated_sql(sql: str, pool: Pool):
    """
    Execute SQL query asynchronously and return rows.

    Args:
        pool (asyncpg.Pool): Database connection pool.
        sql (str): SQL query to execute.

    Returns:
        List[Tuple]: A list of tuples containing query results.
    """
    try:
        start_time = time()
            
        async with pool.acquire() as conn:
            await conn.execute(f"SET search_path TO {DATA_SCHEMA}")
            rows = await conn.fetch(sql)
        
        processing_time = time() - start_time
        logging.info("AI Query Execution Time: %s", processing_time)
        
        return rows
    
    except exceptions.UndefinedColumnError as e:
        error_msg = f"SQL Execution Error: Undefined column '{e.column_name}' in the query."
        logging.error(error_msg)
        raise HTTPException(status_code=status.HTTP_422_UNPROCESSABLE_ENTITY, detail=error_msg)

    except PostgresError as e:
        logging.error(f"SQL Execution Error: {str(e)}")
        raise HTTPException(status_code=status.HTTP_422_UNPROCESSABLE_ENTITY, detail="Invalid SQL query.")

    except Exception as e:
        logging.error("An error occured when executing the AI Generated SQL", exc_info=True)
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Error executing the SQL")


async def fetch_user_details (user_id: str, pool: Pool):

    try:
        usr_id = int(user_id) if user_id.isdigit() else None

        async with pool.acquire() as conn:
            await conn.execute(f"SET search_path TO {USER_DETAILS_SCHEMA}")
            raw_user_details = await conn.fetch("SELECT usr_id, usr_name, usr_personalcode  FROM users_m WHERE usr_id = $1;", usr_id)
            
        if raw_user_details:
            ## Convert each asyncpg Record to a dictionary
            user_details_rows = [dict(row) for row in raw_user_details]
            formated_user_details = tabulate(user_details_rows, headers="keys", tablefmt="simple")
        else:
            formated_user_details = "No user details found for the given user ID."
        
        # print(formated_user_details)
        return formated_user_details
    
    except exceptions.UndefinedColumnError as e:
        error_msg = f"SQL Execution Error: Undefined column '{e.column_name}' in the query."
        logging.error(error_msg)
        raise HTTPException(status_code=status.HTTP_422_UNPROCESSABLE_ENTITY, detail=error_msg)
    
    except PostgresError as e:
        logging.error(f"SQL Execution Error: {str(e)}")
        raise HTTPException(status_code=status.HTTP_422_UNPROCESSABLE_ENTITY, detail="Invalid SQL query.")
    
    except Exception as e:
        logging.error("An error occured when executing the AI Generated SQL", exc_info=True)
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Error executing the SQL")


